const input = $input.first().json;

const missing = [];

if (!input.execution_id) {
  missing.push("execution_id");
}

if (!input.payload) {
  missing.push("payload");
}

if (!input.technical_design) {
  missing.push("technical_design");
}

if (!input.tdd_test_design) {
  missing.push("tdd_test_design");
}

if (!input.tdd_test_design?.unit_tests) {
  missing.push("tdd_test_design.unit_tests");
}

if (!input.tdd_test_design?.api_tests) {
  missing.push("tdd_test_design.api_tests");
}

if (!input.tdd_test_design?.pytest_files) {
  missing.push("tdd_test_design.pytest_files");
}

if (missing.length > 0) {
  return [
    {
      json: {
        ...input,
        wf04_validation: {
          passed: false,
          missing_fields: missing,
          reason: "TDD test design is incomplete"
        },
        current_workflow: "WF04",
        next_workflow: "WF08",
        status: "BLOCKED"
      }
    }
  ];
}

return [
  {
    json: {
      ...input,
      wf04_validation: {
        passed: true,
        missing_fields: []
      }
    }
  }
];

