const input = $input.first().json;

let raw =
  input.output ||
  input.text ||
  input.response ||
  input.content ||
  input.message ||
  input.data;

if (!raw) {
  throw new Error("No AI output found");
}

if (typeof raw !== "string") {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .replace(/,\s*}/g, "}")
  .replace(/,\s*]/g, "]")
  .trim();

const firstBrace = raw.indexOf("{");
const lastBrace = raw.lastIndexOf("}");

if (firstBrace === -1 || lastBrace === -1) {
  throw new Error("No valid JSON object found");
}

const jsonString =
  raw.slice(firstBrace, lastBrace + 1);

let parsed;

try {
  parsed = JSON.parse(jsonString);
}
catch (err) {
  throw new Error(
    "Failed to parse AI JSON output: " + err.message
  );
}

if (!Array.isArray(parsed.files)) {
  throw new Error(
    "Generated output missing files array"
  );
}

return [
  {
    json: {
      ...input,
      wf04_result: parsed
    }
  }
];

const input = $input.first().json;
const result = input.wf04_result || {};

const rawFiles = result.files || [];

const normalizePath = path => {
  return String(path || "")
    .replace(/\\/g, "/")
    .replace(/^\/+/, "")
    .replace(/^.*ai_factory_workspace\/[^/]+\//, "")
    .replace(/^product-app\//, "")
    .replace(/^\.?\//, "");
};

const normalizeContent = content => {
  if (typeof content !== "string") {
    return content;
  }

  return content
    .replace(/\\r\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\t/g, "\t");
};

const normalizedFiles = rawFiles.map(file => {
  return {
    ...file,
    path: normalizePath(file.path),
    content: normalizeContent(file.content)
  };
});

const expectedFromTechnicalDesign =
  Array.isArray(input.technical_design?.project_structure)
    ? input.technical_design.project_structure
    : [];

const expectedFromTdd =
  Array.isArray(input.tdd_test_design?.pytest_files)
    ? input.tdd_test_design.pytest_files
    : [];

const expectedFiles = [
  ...expectedFromTechnicalDesign,
  ...expectedFromTdd
]
  .filter(path => typeof path === "string")
  .map(normalizePath)
  .filter(path => path.length > 0);

const existingPaths =
  normalizedFiles.map(file => file.path);

const missingFiles =
  expectedFiles.filter(path => !existingPaths.includes(path));

const invalidFiles = normalizedFiles.filter(file => {
  const invalidPath =
    !file.path ||
    typeof file.path !== "string" ||
    file.path.includes("ai_factory_workspace") ||
    file.path.includes("n8n_files") ||
    file.path.startsWith("product-app/");

  const invalidContent =
    typeof file.content !== "string";

  const flattenedPython =
    file.path.endsWith(".py") &&
    typeof file.content === "string" &&
    !file.content.includes("\n");

  const flattenedYaml =
    (
      file.path.endsWith(".yml") ||
      file.path.endsWith(".yaml")
    ) &&
    typeof file.content === "string" &&
    !file.content.includes("\n");

  return (
    invalidPath ||
    invalidContent ||
    flattenedPython ||
    flattenedYaml
  );
});

const passed =
  Array.isArray(normalizedFiles) &&
  normalizedFiles.length > 0 &&
  invalidFiles.length === 0 &&
  missingFiles.length === 0 &&
  result.quality_gate?.passed === true;

return [
  {
    json: {
      ...input,
      wf04_result: {
        ...result,
        files: normalizedFiles
      },
      wf04_file_validation: {
        passed,
        file_count: normalizedFiles.length,
        missing_files: missingFiles,
        invalid_files: invalidFiles.map(file => file.path || "unknown")
      }
    }
  }
];

const input = $input.first().json;

const original =
  $('01 - Extract WF03 Payload').item.json;

const payload =
  original.payload;

const result =
  input.wf04_result;

const fileValidation =
  input.wf04_file_validation;

const nextWorkflow =
  fileValidation.passed === true
    ? "WF05"
    : "WF08";

const updatedPayload = {
  ...payload,

  factory: {
    ...payload.factory,
    current_workflow: "WF04",
    next_workflow: nextWorkflow,
    status:
      nextWorkflow === "WF05"
        ? "RUNNING"
        : "BLOCKED",

    workflow_history: [
      ...(payload.factory.workflow_history || []),
      "WF04"
    ]
  },

  code_generation: result.code_generation,

  generated_files: result.files,

  quality_gate: {
    ...(result.quality_gate || {}),
    passed: fileValidation.passed,
    blocking_issues: [
      ...((result.quality_gate || {}).blocking_issues || []),
      ...(fileValidation.missing_files || []).map(file => `Missing required file: ${file}`),
      ...(fileValidation.invalid_files || []).map(file => `Invalid generated file: ${file}`)
    ],
    recommendation:
      fileValidation.passed === true
        ? "CONTINUE"
        : "HUMAN_REVIEW"
  },

  artifacts: [
    ...(payload.artifacts || []),

    {
      workflow: "WF04",
      type: "generated_files",
      name: "generated_files.json",
      content: result.files
    },

    {
      workflow: "WF04",
      type: "code_generation",
      name: "code_generation.json",
      content: result.code_generation
    }
  ]
};

return [
  {
    json: {
      execution_id: original.execution_id,
      payload: updatedPayload,
      current_workflow: "WF04",
      next_workflow: nextWorkflow,
      status: updatedPayload.factory.status,
      quality_gate: updatedPayload.quality_gate
    }
  }
];
